-- Bascule de la résolution OPCO : préfixe DECA (= code département de
-- l'employeur, ex 056 = Morbihan) -> IDCC (convention collective), seul
-- déterminant légal et 1:1 de l'OPCO. L'ancien modèle mappait le département
-- vers un OPCO, ce qui est faux par construction (un département couvre
-- plusieurs OPCO) et imposait un rattrapage manuel sans fin + risque de
-- mis-billing.
--
-- L'API Eduvia n'expose aucun OPCO ; elle fournit company.idcc_code (sync
-- dans eduvia_companies). On embarque ici la correspondance IDCC -> OPCO
-- dérivée de la table officielle France Compétences "Table SIRET-OPCO"
-- (data.gouv.fr 688a210c012cfbf595d7a99a, SIRO_202604, 3,56M lignes) :
-- 922 IDCC réels groupés par OPCO_PROPRIETAIRE (vote majoritaire ; placeholders
-- 9999/9998 et codes agricoles AKTO/OCAPIAT ambigus exclus -> restés
-- unknown_opco, décision humaine).

-- 1) Nouvelle colonne IDCC + validation format (4 chiffres) + index GIN.
ALTER TABLE opcos
  ADD COLUMN IF NOT EXISTS idcc_codes text[] NOT NULL DEFAULT '{}'::text[];

CREATE OR REPLACE FUNCTION public.opcos_check_idcc(idccs text[])
  RETURNS boolean
  LANGUAGE sql
  IMMUTABLE
  SET search_path TO ''
AS $function$
  SELECT bool_and(i ~ '^[0-9]{4}$') FROM unnest(idccs) AS i
$function$;

ALTER TABLE opcos
  DROP CONSTRAINT IF EXISTS opcos_idcc_format;
ALTER TABLE opcos
  ADD CONSTRAINT opcos_idcc_format CHECK (opcos_check_idcc(idcc_codes));

CREATE INDEX IF NOT EXISTS opcos_idcc_codes_gin ON opcos USING gin (idcc_codes);

COMMENT ON COLUMN opcos.idcc_codes IS
  'IDCC (conventions collectives) rattachées à cet OPCO. Clé de résolution OPCO depuis eduvia_companies.idcc_code. Source: France Compétences Table SIRET-OPCO.';

